sys_script.script:
var claimAmount = parseFloat(current.getValue('claim_amount') || 0);
var claimStatus = current.getValue('claim_status');

// Create approval request for high-value claims (over $10,000)
if (claimAmount > 10000 && claimStatus == 'under_review') {
    var approvalGR = new GlideRecord('sysapproval_approver');
    approvalGR.addQuery('document_id', current.getUniqueValue());
    approvalGR.addQuery('source_table', 'x_1945663_insuranc_u_claims_data');
    approvalGR.query();

    if (!approvalGR.hasNext()) {
        // Create new approval request
        var newApproval = new GlideRecord('sysapproval_approver');
        newApproval.initialize();
        newApproval.setValue('document_id', current.getUniqueValue());
        newApproval.setValue('source_table', 'x_1945663_insuranc_u_claims_data');
        newApproval.setValue('approver', current.getValue('adjuster_assigned'));
        newApproval.setValue('state', 'requested');
        newApproval.setValue('comments', 'Auto-generated approval request for high-value claim: $' + claimAmount);

        var approvalSysId = newApproval.insert();

        gs.addInfoMessage('Approval request created for high-value claim: ' + 
                        current.getValue('claim_number') + ' (Amount: $' + claimAmount + ')');
    }
}
